import{_ as t,c as o,o as i,ag as n}from"./chunks/framework.GdcW6lnn.js";const d=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"basics_api/basic-auth.md","filePath":"basics_api/basic-auth.md"}'),r={name:"basics_api/basic-auth.md"};function a(l,s,e,g,c,p){return i(),o("div",null,s[0]||(s[0]=[n('<h3 id="👤-basic-auth-базова-аутентифікація-простии-але-менш-безпечнии-метод-передачі-облікових-даних" tabindex="-1">👤 Basic Auth (Базова аутентифікація): Простий, але менш безпечний метод передачі облікових даних <a class="header-anchor" href="#👤-basic-auth-базова-аутентифікація-простии-але-менш-безпечнии-метод-передачі-облікових-даних" aria-label="Permalink to “👤 Basic Auth (Базова аутентифікація): Простий, але менш безпечний метод передачі облікових даних”">​</a></h3><p><strong>Що це?</strong></p><p>Basic Auth (базова аутентифікація) - це <strong>простий метод аутентифікації</strong>, визначений у стандарті HTTP. У цьому методі клієнт (наприклад, браузер або інша програма) передає свої облікові дані - <strong>ім&#39;я користувача та пароль</strong> - у кожному HTTP-запиті до захищеного ресурсу. Ці облікові дані кодуються за допомогою алгоритму <strong>Base64</strong>.</p><p><strong>Як це працює?</strong></p><ol><li><p><strong>Клієнт отримує облікові дані:</strong> Користувач вводить своє ім&#39;я користувача та пароль у клієнтському застосунку (наприклад, у діалоговому вікні браузера або через інтерфейс програми).</p></li><li><p><strong>Формування рядка облікових даних:</strong> Клієнт об&#39;єднує ім&#39;я користувача та пароль у рядок у форматі <code>username:password</code>.</p></li><li><p><strong>Кодування в Base64:</strong> Клієнт кодує цей рядок у форматі Base64. Base64 - це алгоритм кодування, який перетворює бінарні дані в текстовий формат ASCII. <strong>Важливо розуміти, що Base64 - це не шифрування, і закодований рядок легко декодувати.</strong></p></li><li><p><strong>Передача в заголовку <code>Authorization</code>:</strong> Клієнт додає HTTP-заголовок <code>Authorization</code> до кожного запиту до захищеного ресурсу. Значенням цього заголовка є рядок <code>Basic </code>, за яким слідує закодований у Base64 рядок облікових даних.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Authorization: Basic dXNlcm5hbWU6cGFzc3dvcmQ=</span></span></code></pre></div><p>(де <code>dXNlcm5hbWU6cGFzc3dvcmQ=</code> є результатом кодування <code>username:password</code> в Base64).</p></li><li><p><strong>Перевірка облікових даних на сервері:</strong> Сервер API отримує запит, витягує значення заголовка <code>Authorization</code>, декодує його з Base64, отримуючи ім&#39;я користувача та пароль.</p></li><li><p><strong>Аутентифікація:</strong> Сервер порівнює отримані облікові дані з інформацією про користувачів, що зберігається на сервері (наприклад, у базі даних).</p></li><li><p><strong>Надання доступу або відмова:</strong> Якщо облікові дані є дійсними, сервер обробляє запит і повертає відповідь. В іншому випадку сервер зазвичай повертає помилку <code>401 Unauthorized</code>, часто з заголовком <code>WWW-Authenticate: Basic realm=&quot;Realm Name&quot;</code>, який може спонукати браузер відобразити діалогове вікно для введення облікових даних.</p></li></ol><p><strong>Переваги Basic Auth:</strong></p><ul><li><strong>Простота реалізації:</strong> Basic Auth дуже легко реалізувати як на стороні клієнта, так і на стороні сервера.</li><li><strong>Широка підтримка:</strong> Підтримується більшістю HTTP-клієнтів (включаючи браузери) та веб-серверів без необхідності встановлення додаткових бібліотек або програмного забезпечення.</li><li><strong>Легкість тестування:</strong> Можна легко тестувати за допомогою простих HTTP-клієнтів, таких як <code>curl</code>, або вбудованих інструментів браузера.</li></ul><p><strong>Недоліки Basic Auth:</strong></p><ul><li><p><strong>Безпека:</strong></p><ul><li><strong>Відсутність шифрування:</strong> Облікові дані лише кодуються в Base64, що не є шифруванням і легко може бути декодовано.</li><li><strong>Передача облікових даних при кожному запиті:</strong> Облікові дані передаються з кожним запитом, що збільшує ризик їх перехоплення, особливо якщо не використовується HTTPS.</li><li><strong>Немає механізму виходу (logout):</strong> Після того, як браузер отримав облікові дані, він зазвичай продовжує надсилати їх у наступних запитах до того ж realm, поки вкладка не буде закрита або не буде очищено кеш браузера. Немає стандартного способу для користувача явно &quot;вийти&quot; з сесії Basic Auth на стороні сервера.</li><li><strong>Обмежені можливості авторизації:</strong> Basic Auth в першу чергу є механізмом аутентифікації та не надає гнучких можливостей для керування правами доступу на рівні користувача або ролей.</li></ul></li><li><p><strong>Зручність використання:</strong></p><ul><li>Браузери зазвичай відображають стандартне діалогове вікно для введення облікових даних, яке може бути не дуже зручним для користувачів складних веб-додатків.</li><li>Для небраузерних клієнтів розробникам потрібно самостійно реалізовувати логіку зберігання та передачі облікових даних.</li></ul></li></ul><p><strong>Коли використовувати Basic Auth:</strong></p><p>Basic Auth може бути прийнятним у таких сценаріях:</p><ul><li><strong>Прості внутрішні API:</strong> Для API, які використовуються лише внутрішніми системами та де безпека забезпечується на інших рівнях (наприклад, мережева безпека).</li><li><strong>API для невеликої кількості довірених клієнтів:</strong> Якщо доступ до API обмежений невеликою кількістю відомих та довірених програм.</li><li><strong>Тестування та налагодження:</strong> Може бути зручним для швидкого тестування API під час розробки.</li><li><strong>У поєднанні з HTTPS:</strong> Використання Basic Auth <strong>завжди повинно супроводжуватися використанням HTTPS (TLS/SSL)</strong> для шифрування трафіку та захисту облікових даних під час передачі. <strong>Використання Basic Auth через незахищене з&#39;єднання HTTP є вкрай небезпечним.</strong></li></ul><p><strong>Коли слід уникати Basic Auth:</strong></p><ul><li><strong>Публічні API:</strong> Для API, які доступні широкому загалу розробників.</li><li><strong>API, що обробляють конфіденційні дані:</strong> Через низький рівень безпеки.</li><li><strong>Сучасні веб-додатки:</strong> Інші методи аутентифікації, такі як OAuth 2.0 або JWT, є більш гнучкими та безпечними.</li><li><strong>Мобільні додатки:</strong> Зберігання облікових даних у мобільних додатках є складним завданням з точки зору безпеки.</li></ul><p><strong>Висновок:</strong></p><p>Basic Auth є найпростішим методом HTTP-аутентифікації, але його простота супроводжується значними обмеженнями в безпеці. Його слід використовувати з обережністю та <strong>завжди в поєднанні з HTTPS</strong>. Для більшості сучасних API та веб-додатків існують більш безпечні та гнучкі альтернативи, які слід розглядати в першу чергу.</p>',16)]))}const h=t(r,[["render",a]]);export{d as __pageData,h as default};
